UPDATE reactions
SET
  title = v.title,
  type = v.type,
  description = v.description,
  observation = v.observation,
  explanation = v.explanation,
  safety = v.safety,
  safety_note = v.safety,
  data = COALESCE(reactions.data, '{}'::jsonb) || v.data::jsonb,
  updated_at = now()
FROM (VALUES
  ('agno3_nacl', 'Осаждение хлорида серебра', 'осаждение', 'Образуется белый осадок AgCl.', 'Раствор мутнеет, на дне появляется белый осадок.', 'Ионы Ag+ и Cl- образуют малорастворимый хлорид серебра.', 'Соли серебра оставляют пятна, работайте аккуратно.', '{"name":"Осаждение хлорида серебра","title":"Осаждение хлорида серебра","type":"осаждение","expectedEffect":"белый осадок AgCl","message":"Образовался белый осадок AgCl.","observation":"Раствор мутнеет, на дне появляется белый осадок.","explanation":"Ионы Ag+ и Cl- образуют малорастворимый хлорид серебра.","safetyNote":"Соли серебра оставляют пятна, работайте аккуратно."}'),
  ('hcl_nahco3', 'Кислота и гидрокарбонат: выделение газа', 'выделение газа', 'Выделяется углекислый газ.', 'В сосуде появляются пузырьки CO2.', 'Кислота реагирует с гидрокарбонатом с образованием соли, воды и углекислого газа.', 'Не закрывайте сосуд герметично при выделении газа.', '{"name":"Кислота и гидрокарбонат: выделение газа","title":"Кислота и гидрокарбонат: выделение газа","type":"выделение газа","expectedEffect":"пузырьки CO2","message":"Выделяется углекислый газ.","observation":"В сосуде появляются пузырьки CO2.","explanation":"Кислота реагирует с гидрокарбонатом с образованием соли, воды и углекислого газа.","safetyNote":"Не закрывайте сосуд герметично при выделении газа."}'),
  ('cuso4_naoh', 'Осаждение гидроксида меди(II)', 'осаждение', 'Образуется голубой осадок.', 'Появляется голубой студенистый осадок.', 'Ионы Cu2+ соединяются с OH- и образуют малорастворимый Cu(OH)2.', 'Растворы солей меди не пробуйте на вкус и не допускайте попадания на кожу.', '{"name":"Осаждение гидроксида меди(II)","title":"Осаждение гидроксида меди(II)","type":"осаждение","expectedEffect":"голубой осадок Cu(OH)2","message":"Образовался голубой осадок гидроксида меди(II).","observation":"Появляется голубой студенистый осадок.","explanation":"Ионы Cu2+ соединяются с OH- и образуют малорастворимый Cu(OH)2.","safetyNote":"Растворы солей меди не пробуйте на вкус и не допускайте попадания на кожу."}'),
  ('fecl3_naoh', 'Осаждение гидроксида железа(III)', 'осаждение', 'Образуется бурый осадок.', 'В растворе появляется бурый осадок.', 'Ионы Fe3+ и OH- образуют малорастворимый гидроксид железа(III).', 'Работайте аккуратно, избегайте разбрызгивания.', '{"name":"Осаждение гидроксида железа(III)","title":"Осаждение гидроксида железа(III)","type":"осаждение","expectedEffect":"бурый осадок Fe(OH)3","message":"Образовался бурый осадок гидроксида железа(III).","observation":"В растворе появляется бурый осадок.","explanation":"Ионы Fe3+ и OH- образуют малорастворимый гидроксид железа(III).","safetyNote":"Работайте аккуратно, избегайте разбрызгивания."}'),
  ('h2o_heat', 'Нагревание воды до пара', 'нагревание', 'Безопасная демонстрация перехода воды в пар.', 'Над сосудом появляется пар.', 'При нагревании вода переходит из жидкого состояния в газообразное; новое вещество не образуется.', 'Используйте слабый нагрев и не нагревайте закрытый сосуд.', '{"name":"Нагревание воды до пара","title":"Нагревание воды до пара","type":"нагревание","expectedEffect":"лёгкий пар над сосудом","message":"Вода нагревается и испаряется.","observation":"Над сосудом появляется пар.","explanation":"При нагревании вода переходит из жидкого состояния в газообразное; новое вещество не образуется.","safetyNote":"Используйте слабый нагрев и не нагревайте закрытый сосуд."}'),
  ('caco3_hcl', 'Получение углекислого газа', 'выделение газа', 'Карбонат с кислотой выделяет углекислый газ.', 'В сосуде появляются пузырьки, газ отводится через трубку.', 'Карбонат кальция реагирует с кислотой: образуются соль, вода и углекислый газ.', 'Кислоту добавляйте малыми порциями, газоотвод не направляйте к лицу.', '{"name":"Получение углекислого газа","title":"Получение углекислого газа","type":"выделение газа","expectedEffect":"пузырьки CO2 и газоотвод","message":"Реакция прошла успешно: выделяется CO2.","observation":"В сосуде появляются пузырьки, газ отводится через трубку.","explanation":"Карбонат кальция реагирует с кислотой: образуются соль, вода и углекислый газ.","safetyNote":"Кислоту добавляйте малыми порциями, газоотвод не направляйте к лицу."}')
) AS v(id, title, type, description, observation, explanation, safety, data)
WHERE reactions.id = v.id;
